import os
import re
from datetime import datetime, timedelta

LOG_DIR = '/app/logs'
OUTPUT_FILE = '/app/summary.csv'

# Reference date (today)
TODAY = datetime(2025, 8, 12).date()

# Date ranges
SEVEN_DAYS_AGO = TODAY - timedelta(days=6)  # inclusive of today and 6 days before = 7 days
THIRTY_DAYS_AGO = TODAY - timedelta(days=29)  # inclusive of today and 29 days before = 30 days
MONTH_START = TODAY.replace(day=1)

# Period definitions
def in_today(d):
    return d == TODAY

def in_last_7_days(d):
    return SEVEN_DAYS_AGO <= d <= TODAY

def in_last_30_days(d):
    return THIRTY_DAYS_AGO <= d <= TODAY

def in_month_to_date(d):
    return MONTH_START <= d <= TODAY

def in_total(d):
    return True

PERIODS = {
    'today': in_today,
    'last_7_days': in_last_7_days,
    'last_30_days': in_last_30_days,
    'month_to_date': in_month_to_date,
    'total': in_total
}

SEVERITIES = ['ERROR', 'WARNING', 'INFO']

# Initialize counters: period -> severity -> count
counts = {period: {sev: 0 for sev in SEVERITIES} for period in PERIODS}

# Pattern to extract date from filename
DATE_PATTERN = re.compile(r'^(\d{4}-\d{2}-\d{2})_')

# Process each log file
for filename in os.listdir(LOG_DIR):
    if not filename.endswith('.log'):
        continue
    # Extract date from filename
    match = DATE_PATTERN.match(filename)
    if not match:
        continue
    date_str = match.group(1)
    try:
        file_date = datetime.strptime(date_str, '%Y-%m-%d').date()
    except ValueError:
        continue

    # Determine which periods this file belongs to
    active_periods = [period for period, condition in PERIODS.items() if condition(file_date)]
    if not active_periods:
        continue

    # Count severities in this file
    filepath = os.path.join(LOG_DIR, filename)
    file_counts = {sev: 0 for sev in SEVERITIES}
    try:
        with open(filepath, 'r') as f:
            for line in f:
                # Look for [SEVERITY] pattern
                if '[ERROR]' in line:
                    file_counts['ERROR'] += 1
                if '[WARNING]' in line:
                    file_counts['WARNING'] += 1
                if '[INFO]' in line:
                    file_counts['INFO'] += 1
    except Exception as e:
        print(f"Error reading {filepath}: {e}")
        continue

    # Add to counts for each active period
    for period in active_periods:
        for sev in SEVERITIES:
            counts[period][sev] += file_counts[sev]

# Write CSV
with open(OUTPUT_FILE, 'w') as f:
    f.write('period,severity,count\\n')
    for period in PERIODS:
        for sev in SEVERITIES:
            f.write(f'{period},{sev},{counts[period][sev]}\\n')

print(f'Summary written to {OUTPUT_FILE}')"}

